int main() {
    int fd[2];
    if (pipe(fd) == -1) {
        std::cerr << "Erreur à la création du pipe !" << std::endl;
        return -1;
    }

    pid_t pid = fork();
    if (pid == -1) {
        std::cerr << "Erreur au fork !" << std::endl;
        return -1;
    }

    if (pid == 0) { // Code du processus fils
        close(fd[1]); // On ferme l'écriture
        dup2(fd[0], STDIN_FILENO); // On redirige l'entrée standard vers le pipe
        close(fd[0]); // On ferme le pipe de lecture
        execlp("votre_programme", "votre_programme", NULL); // Remplace le processus par votre programme
        std::cerr << "Erreur d'exécution du programme !" << std::endl;
        _exit(-1);
    } else { // Code du processus père
        close(fd[0]); // On ferme la lecture
        dup2(fd[1], STDOUT_FILENO); // On redirige la sortie standard vers le pipe
        close(fd[1]); // On ferme le pipe d'écriture
    }

    return 0;
}
